package com.icbc.api;



import java.util.ArrayList;
import java.util.List;

import org.junit.Test;

import com.icbc.api.request.SplitQueryRequestV1;
import com.icbc.api.request.SplitQueryRequestV1.SplitQueryRequestV1Biz;
import com.icbc.api.response.SplitQueryResponseV1;


public class JftSplitQueryTestV1 {
	protected static final String MY_PRIVATE_KEY = "-----请使用正确的APP私钥-----";

    protected static final String APIGW_PUBLIC_KEY = "[需替换]工行API网关公钥，请向工行联系获取";

	protected static final String APP_ID = "[需替换]APP的编号";
    
    protected static final String AES_Key = "[需替换]应用方加密串，与工行API开放平台一致";


    public void test_split(){
        DefaultIcbcClient client = new DefaultIcbcClient(APP_ID,"RSA2", MY_PRIVATE_KEY,"UTF-8", 
				"json",APIGW_PUBLIC_KEY,"AES",AES_Key, "", "");
        SplitQueryRequestV1 request = new SplitQueryRequestV1();
        request.setServiceUrl("[需替换]工行API网关地址/api/jft/api/split/query/V1");
        
        SplitQueryRequestV1Biz bizContent = new SplitQueryRequestV1Biz();
       
        bizContent.setAppId(APP_ID);//APP编号
        bizContent.setOutOrderId("20200202002");//平台对接方业务ID
        bizContent.setOutSplitId("1224536");//子商户标识：提交支付请求的子商户编号
    
        
        request.setBizContent(bizContent);
        
        SplitQueryResponseV1 response;
        try {
			response = client.execute(request, System.currentTimeMillis()+"");
			
			if (response.isSuccess()) {
				// 业务成功处理
				System.out.println(response.getReturnCode());
			} else {
				// 失败
			}
		} catch (IcbcApiException e) {
			e.printStackTrace();
		}
    }
    public static void main(String[] args) {
        new JftSplitQueryTestV1().test_split();
    }
											
	
}

